/* 공지사항 조회수 증가 notice.updateNoticeViewCnt */
UPDATE TB_NOTICE
SET
    VIEW_CNT = VIEW_CNT + 1
WHERE NOTICE_ID = #{noticeId}

/* 대표 공지 초기화 notice.resetNoticeFeaturedYn */
UPDATE TB_NOTICE
SET
    FEATURED_YN = 'N'
WHERE FEATURED_YN = 'Y'

    AND NOTICE_ID != #{noticeId}

mapper.insert:
/* 공지사항 등록 notice.insertNotice */
INSERT INTO TB_NOTICE (
    NOTICE_ID
    , TITLE
    , CONTENT
    , PIN_YN
    , VIEW_CNT
    , FEATURED_YN
    , USE_YN
    , CRTR_ID
    , CREATE_DT
)
VALUES (
    #{noticeId}
    , #{title}
    , #{content}
    , IFNULL(#{pinYn}, 'N')
    , IFNULL(#{viewCnt}, 0)
    , IFNULL(#{featuredYn}, 'N')
    , IFNULL(#{useYn}, 'Y')
    , #{crtrId}
    , NOW()
)

mapper.update:
/* 공지사항 수정 notice.updateNotice */
UPDATE TB_NOTICE
SET
    TITLE = #{title}
    , CONTENT = #{content}
    , PIN_YN = IFNULL(#{pinYn}, 'N')
    , VIEW_CNT = IFNULL(#{viewCnt}, 0)
    , FEATURED_YN = IFNULL(#{featuredYn}, 'N')
    , USE_YN = IFNULL(#{useYn}, 'Y')
    , MODIFY_DT = NOW()
WHERE NOTICE_ID = #{noticeId}

/* 공지사항 삭제 notice.deleteNotice */
UPDATE TB_NOTICE
SET
    USE_YN = 'N'
    , MODIFY_DT = NOW()
WHERE NOTICE_ID = #{noticeId}
